import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import "./studentDashboard.css";
import { useNavigate } from "react-router-dom";

export default function StudentDashboard() {
  const studentId = localStorage.getItem("userId");
  const [activeTab, setActiveTab] = useState("overview");
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("userId");
    navigate("/login");
  };

  const [student, setStudent] = useState(null);
  const [mentor, setMentor] = useState(null);
  const [mentors, setMentors] = useState([]);
  const [meetings, setMeetings] = useState([]);
  const [availability, setAvailability] = useState([]);
  const [reports, setReports] = useState([]);

  const [loading, setLoading] = useState({
    student: false,
    mentors: false,
    meetings: false,
    availability: false,
    reports: false,
  });
  const [error, setError] = useState(null);

  const [projectData, setProjectData] = useState({
    mentor_id: "",
    project_title: "",
    description: "",
    domain: "",
    time_required: "",
    skills_required: "",
  });

  const [selectedSlot, setSelectedSlot] = useState("");
  const [selectedFile, setSelectedFile] = useState(null);
  const [reportTitle, setReportTitle] = useState("");
  const [reportDescription, setReportDescription] = useState("");
  const [reportType, setReportType] = useState("progress");

  const setLoadingKey = (key, val) => setLoading((prev) => ({ ...prev, [key]: val }));

  const fetchMentors = async () => {
    setLoadingKey("mentors", true);
    try {
      const res = await axios.get("http://localhost:5050/api/students/mentors");
      setMentors(Array.isArray(res.data) ? res.data : []);
    } catch (e) {
      setError("Failed to load mentors.");
    } finally {
      setLoadingKey("mentors", false);
    }
  };

  const fetchStudent = async () => {
    if (!studentId) return;
    setLoadingKey("student", true);
    try {
      const res = await axios.get(`http://localhost:5050/api/students/me`);
      setStudent(res.data || null);
      if (res.data && res.data.mentor_id) {
        await fetchMentorById(res.data.mentor_id);
        await fetchAvailability(res.data.mentor_id);
      } else {
        setMentor(null);
        setAvailability([]);
      }
    } catch (e) {
      setError("Failed to load student info.");
    } finally {
      setLoadingKey("student", false);
    }
  };

  const fetchMentorById = async (mentorId) => {
    if (!mentorId) return;
    try {
      const res = await axios.get(`http://localhost:5050/api/mentors/${mentorId}`);
      setMentor(res.data || null);
    } catch (e) {
      setMentor(null);
    }
  };

  const fetchMeetings = async () => {
    if (!studentId) return;
    setLoadingKey("meetings", true);
    try {
      const res = await axios.get(`http://localhost:5050/api/students/meetings/${studentId}`);
      setMeetings(Array.isArray(res.data) ? res.data : []);
    } catch (e) {
      setMeetings([]);
    } finally {
      setLoadingKey("meetings", false);
    }
  };

  const fetchAvailability = async (mentorIdParam) => {
    const mid = mentorIdParam || (mentor && mentor.sno);
    if (!mid) return;
    setLoadingKey("availability", true);
    try {
      const res = await axios.get(`http://localhost:5050/api/mentors/availability/${mid}`);
      setAvailability(Array.isArray(res.data) ? res.data : []);
    } catch (e) {
      setAvailability([]);
    } finally {
      setLoadingKey("availability", false);
    }
  };

  const fetchReports = async () => {
    if (!studentId) return;
    setLoadingKey("reports", true);
    try {
      const res = await axios.get(`http://localhost:5050/api/students/reports/${studentId}`);
      setReports(Array.isArray(res.data) ? res.data : []);
    } catch (e) {
      setReports([]);
    } finally {
      setLoadingKey("reports", false);
    }
  };

  useEffect(() => {
    setError(null);
    fetchMentors();
    fetchStudent();
    fetchMeetings();
    fetchReports();
  }, [studentId]);

  useEffect(() => {
    if (mentor && mentor.sno) fetchAvailability(mentor.sno);
  }, [mentor]);

  const mentorOptions = useMemo(
    () =>
      (mentors || []).map((m) => ({
        value: m.sno,
        label: `${m.facultyname} (${m.specialization || "—"})`,
      })),
    [mentors]
  );

  const handleProjectChange = (e) => {
    setProjectData({ ...projectData, [e.target.name]: e.target.value });
  };

  const handleProjectSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5050/api/students/request", projectData);
      setProjectData({
        mentor_id: "",
        project_title: "",
        description: "",
        domain: "",
        time_required: "",
        skills_required: "",
      });
    } catch (e) {
      setError("Failed to submit project.");
    }
  };

  const handleSlotBooking = async () => {
    if (!selectedSlot || !mentor) return;
    const [meeting_date, meeting_time] = selectedSlot.split(" ");
    try {
      await axios.post("http://localhost:5050/api/students/meetings", {
        mentor_id: mentor.sno,
        meeting_date,
        meeting_time,
      });
      setSelectedSlot("");
      fetchMeetings();
    } catch (e) {
      setError("Failed to book meeting.");
    }
  };

  const handleReportUpload = async (e) => {
    e.preventDefault();
    if (!selectedFile) return;
    const formData = new FormData();
    formData.append("file", selectedFile);
    formData.append("mentor_id", mentor ? mentor.sno : "");
    formData.append("title", reportTitle || selectedFile.name);
    formData.append("description", reportDescription);
    formData.append("type", reportType);
    try {
      await axios.post("http://localhost:5050/api/students/reports/upload", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      setSelectedFile(null);
      setReportTitle("");
      setReportDescription("");
      setReportType("progress");
      fetchReports();
    } catch (e) {
      setError("Failed to upload report.");
    }
  };

  const handleRequestFromMentorCard = (mentorId) => {
    setProjectData({ ...projectData, mentor_id: mentorId });
    setActiveTab("project");
  };

  return (
    <div className="student-dashboard">
      <div className="dashboard-header">
        <h1>Student Dashboard</h1>
        <button className="logout-btn" onClick={handleLogout}>Logout</button>
      </div>

      <div className="tab-buttons">
        <button onClick={() => setActiveTab("overview")} className={activeTab === "overview" ? "active" : ""}>Overview</button>
        <button onClick={() => setActiveTab("mentors")} className={activeTab === "mentors" ? "active" : ""}>Mentors</button>
        <button onClick={() => setActiveTab("project")} className={activeTab === "project" ? "active" : ""}>Project</button>
      </div>

      {error && <div className="error-banner">{error}</div>}

      {activeTab === "overview" && (
        <div className="overview-tab">
          <h2>Welcome, {student?.studentname || "Student"} 👋</h2>
          <div className="overview-sections">
            <div className="section-card">
              <h3>Profile</h3>
              {loading.student ? (
                <p>Loading profile…</p>
              ) : student ? (
                <>
                  <p><strong>Name:</strong> {student.studentname}</p>
                  <p><strong>Email:</strong> {student.Email}</p>
                  <p><strong>Semester:</strong> {student.semester}</p>
                </>
              ) : (
                <p>No profile data</p>
              )}
            </div>

            <div className="section-card">
              <h3>Mentor</h3>
              {mentor ? (
                <>
                  <p><strong>Name:</strong> {mentor.facultyname}</p>
                  <p><strong>Specialization:</strong> {mentor.specialization}</p>
                </>
              ) : (
                <p>No mentor assigned yet.</p>
              )}
            </div>

            <div className="section-card">
              <h3>Meetings</h3>
              {loading.meetings ? (
                <p>Loading meetings…</p>
              ) : meetings.length === 0 ? (
                <p>No upcoming meetings</p>
              ) : (
                meetings.map((m) => (
                  <p key={m.id}>
                    {m.meeting_date} at {m.meeting_time} — {m.topic}
                  </p>
                ))
              )}
              <hr />
              <h4>Book a Slot</h4>
              {mentor ? (
                <>
                  {loading.availability ? (
                    <p>Loading availability…</p>
                  ) : availability.length === 0 ? (
                    <p>No available slots from your mentor.</p>
                  ) : (
                    <>
                      <select value={selectedSlot} onChange={(e) => setSelectedSlot(e.target.value)}>
                        <option value="">Select slot</option>
                        {availability.map((a) => (
                          <option key={a.id} value={`${a.day} ${a.start_time}`}>
                            {`${a.day} ${a.start_time} - ${a.end_time}`}
                          </option>
                        ))}
                      </select>
                      <button onClick={handleSlotBooking}>Book Meeting</button>
                    </>
                  )}
                </>
              ) : (
                <p>Assign/select a mentor to book meetings.</p>
              )}
            </div>

            <div className="section-card">
              <h3>Reports</h3>
              <form onSubmit={handleReportUpload}>
                <input type="text" placeholder="Title" value={reportTitle} onChange={(e) => setReportTitle(e.target.value)} />
                <textarea placeholder="Description" value={reportDescription} onChange={(e) => setReportDescription(e.target.value)} />
                <select value={reportType} onChange={(e) => setReportType(e.target.value)}>
                  <option value="progress">Progress</option>
                  <option value="final">Final</option>
                </select>
                <input type="file" onChange={(e) => setSelectedFile(e.target.files[0])} />
                <button type="submit">Upload Report</button>
              </form>
              <h4>Uploaded Reports</h4>
              {loading.reports ? (
                <p>Loading reports…</p>
              ) : reports.length === 0 ? (
                <p>No reports uploaded yet</p>
              ) : (
                <ul>
                  {reports.map((r) => (
                    <li key={r.id}>
                      {r.title} — {r.status}
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        </div>
      )}

      {activeTab === "mentors" && (
        <div className="mentors-container">
          {loading.mentors ? (
            <p>Loading mentors…</p>
          ) : mentors.length === 0 ? (
            <p>No mentors found.</p>
          ) : (
            mentors.map((m) => (
              <div key={m.sno} className="mentor-card">
                <h3>{m.facultyname}</h3>
                <p><strong>Specialization:</strong> {m.specialization || "—"}</p>
                <p><strong>Email:</strong> {m.Email}</p>
                <p><strong>Designation:</strong> {m.designation || "—"}</p>
                <button onClick={() => handleRequestFromMentorCard(m.sno)}>Request Mentor</button>
              </div>
            ))
          )}
        </div>
      )}

      {activeTab === "project" && (
        <div className="project-vertical">
          <h3>Submit Project Idea</h3>
          <form onSubmit={handleProjectSubmit}>
            <label>Mentor:</label>
            <select name="mentor_id" value={projectData.mentor_id} onChange={handleProjectChange} required>
              <option value="">Select Mentor</option>
              {mentorOptions.map((opt) => (
                <option key={opt.value} value={opt.value}>
                  {opt.label}
                </option>
              ))}
            </select>

            <label>Project Title:</label>
            <input type="text" name="project_title" value={projectData.project_title} onChange={handleProjectChange} required />

            <label>Domain:</label>
            <input type="text" name="domain" value={projectData.domain} onChange={handleProjectChange} />

            <label>Time Required:</label>
            <input type="text" name="time_required" value={projectData.time_required} onChange={handleProjectChange} />

            <label>Skills Required:</label>
            <input type="text" name="skills_required" value={projectData.skills_required} onChange={handleProjectChange} />

            <label>Project Overview:</label>
            <textarea name="description" value={projectData.description} onChange={handleProjectChange} rows="4" />

            <button type="submit">Submit Project</button>
          </form>
        </div>
      )}
    </div>
  );
}
